do	if type(getrlyunyz) ~= 'function' then		gg.alert('请使用RLGG执行')		os.exit()		return	end	local info = {	    example_version = '1.0.3',		name = '明日香',		appid = '100903',		appkey = 'c32b883BUb5M6Bcx',		rc4key = '76y7Qq4141R6Y6Ry',		version = '1.5',		mi_type = '0'	}	local rlyunyz = getrlyunyz(info)	local ret = rlyunyz.start()	if not ret or not isTable(ret) or ret.sign ~= '804a591b102080e5a2817b01d5f7e4f3' then		os.exit()		return	endendgg.alert('RLGG')local floatingWindowManager = require('floatingWindowManager')floatingWindowManager:init()local function baiduTTS(txt)	gg.playMusic("https://fanyi.baidu.com/gettts?lan=zh&text="..txt.."&spd=5&source=wise")endbaiduTTS("欢迎使用明日香")local saved = {}local function record(name, results)	if not saved[name] then saved[name] = {} end	for i = 1, #results do		table.insert(saved[name], {addr = results[i].address, val = results[i].value})	endendlocal function restore(name)	if saved[name] then		for i = 1, #saved[name] do			gg.setValues({{address = saved[name][i].addr, flags = gg.TYPE_FLOAT, value = saved[name][i].val}})		end		saved[name] = nil	endendlocal function sw(name, onFunc, offFunc)	return {		LinearLayout,		padding = {'0dp','0dp','0dp','0dp'},		layout_marginTop = '5dp',		{			Switch,			layout_marginLeft = '0dp',			text = name,			textColor = "#FFFFFF",			gravity = "center",			layout_height = "40dp",			layout_width = "match_parent",			background = luajava.loadlayout {				GradientDrawable,				color = '0x80b5dbff',				cornerRadius = '10dp'			},			onCheckedChange = function(CompoundButton, state)				luajava.newThread(function()					if state then						baiduTTS(name.."已开启")						pcall(onFunc)					else						pcall(offFunc)					end				end):start()			end		}	}endlocal function btn(name, func)	return {		Button,		background = {			GradientDrawable,			cornerRadius = '10dp',			color = '0x80b5dbff',		},		layout_width = 'match_parent',		layout_height = '40dp',		layout_margin = '2dp',		text = name,		textSize = '16sp',		textColor = '#FFFFFF',		onClick = function()			pcall(func)		end	}endlocal function f2000(state)	if not state then		restore("2000匹")		gg.toast("2000匹已关闭")		baiduTTS("2000匹已关闭")		return	end	saved["2000匹"] = nil	local total = 0	gg.clearResults()	gg.setRanges(16384)	gg.searchNumber("360", gg.TYPE_FLOAT, false, gg.SIGN_EQUAL, 0, -1)	gg.searchNumber("", gg.TYPE_FLOAT, false, gg.SIGN_EQUAL, 0, -1)	local r = gg.getResults(500)	if #r > 0 then		record("2000匹", r)		gg.editAll("2000", gg.TYPE_FLOAT)		total = total + #r	end	gg.clearResults()	gg.setRanges(16384)	gg.searchNumber("500", gg.TYPE_FLOAT, false, gg.SIGN_EQUAL, 0, -1)	gg.searchNumber("", gg.TYPE_FLOAT, false, gg.SIGN_EQUAL, 0, -1)	local r2 = gg.getResults(500)	if #r2 > 0 then		record("2000匹", r2)		gg.editAll("3000", gg.TYPE_FLOAT)		total = total + #r2	end	gg.clearResults()	if total > 0 then		gg.toast("2000匹开启成功,共修改"..total.."条数据")		baiduTTS("2000匹开启成功")	else		gg.toast("2000匹开启失败")		baiduTTS("2000匹开启失败")	endendlocal function fxm(state)	if not state then		restore("斜秒专用")		gg.toast("斜秒专用已关闭")		baiduTTS("斜秒专用已关闭")		return	end	saved["斜秒专用"] = nil	local total = 0	gg.clearResults()	gg.setRanges(16384)	gg.searchNumber("360", gg.TYPE_FLOAT, false, gg.SIGN_EQUAL, 0, -1)	gg.searchNumber("", gg.TYPE_FLOAT, false, gg.SIGN_EQUAL, 0, -1)	local r = gg.getResults(500)	if #r > 0 then		record("斜秒专用", r)		gg.editAll("1511", gg.TYPE_FLOAT)		total = total + #r	end	gg.clearResults()	gg.setRanges(16384)	gg.searchNumber("500", gg.TYPE_FLOAT, false, gg.SIGN_EQUAL, 0, -1)	gg.searchNumber("", gg.TYPE_FLOAT, false, gg.SIGN_EQUAL, 0, -1)	local r2 = gg.getResults(500)	if #r2 > 0 then		record("斜秒专用", r2)		gg.editAll("2259", gg.TYPE_FLOAT)		total = total + #r2	end	gg.clearResults()	gg.setRanges(16384)	gg.searchNumber("6300", gg.TYPE_FLOAT, false, gg.SIGN_EQUAL, 0, -1)	gg.searchNumber("", gg.TYPE_FLOAT, false, gg